9	export function nextGeneration(cells: Cell[]): Cell[] {
10	  const liveSet = new Set(cells.map(toKey));
11	  const neighborCounts = countNeighbors(cells);
12	
13	  const next: Cell[] = [];
14	  for (const [key, count] of neighborCounts) {
15	    if (survives(count, liveSet.has(key))) {
16	      next.push(fromKey(key));
17	    }
18	  }
19	  return next;
20	}
