22	function countNeighbors(cells: Cell[]): Map<string, number> {
23	  const counts = new Map<string, number>();
24	  for (const [x, y] of cells) {
25	    for (let dx = -1; dx <= 1; dx++) {
26	      for (let dy = -1; dy <= 1; dy++) {
27	        if (dx === 0 && dy === 0) continue;
28	        const key = toKey([x + dx, y + dy]);
29	        counts.set(key, (counts.get(key) ?? 0) + 1);
30	      }
31	    }
32	  }
33	  return counts;
34	}
35	
36	function survives(neighborCount: number, isAlive: boolean): boolean {
37	  return neighborCount === 3 || (neighborCount === 2 && isAlive);
38	}
