    const input: Cell[] = [[0, 0], [0, 1], [0, 2]];
    const expected: Cell[] = [[-1, 1], [0, 1], [1, 1]];
    const result = nextGeneration(input);
    expect(new Set(result.map(([x, y]) => `${x},${y}`))).toEqual(
      new Set(expected.map(([x, y]) => `${x},${y}`))
    );
  });

